import React, { useState, useEffect } from 'react';

// --- 1. KOMPONEN UI: STAT CARD ---
const StatCard = ({ icon, value, label, color }) => (
  <div style={styles.statCard}>
    <div style={{ ...styles.statIconBox, backgroundColor: `${color}15`, color: color }}>{icon}</div>
    <div>
      <div style={styles.statValue}>{value}</div>
      <div style={styles.statLabel}>{label}</div>
    </div>
  </div>
);

// --- 2. KOMPONEN UI: PROGRESS BAR (DENGAN GRADIENT) ---
const CapacityBar = ({ percentage }) => {
  const isFull = percentage > 85;
  const color = isFull ? 'linear-gradient(90deg, #ff4d4d, #f9ca24)' : 'linear-gradient(90deg, #2ecc71, #00b894)';
  return (
    <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
      <div style={styles.progressBar}>
        <div style={{
          ...styles.progressFill,
          width: `${percentage}%`,
          background: color,
        }}></div>
      </div>
      <span style={{ fontSize: '12px', fontWeight: '700', color: '#2d3436' }}>{Math.round(percentage)}%</span>
    </div>
  );
};

// --- 3. KOMPONEN UTAMA: DASHBOARD ---
function Dashboard() {
  const [trashData, setTrashData] = useState([]);
  const [adminData, setAdminData] = useState([]);
  const [dailyStats, setDailyStats] = useState([]);
  const [activeAdmin, setActiveAdmin] = useState('');
  const [activeMenu, setActiveMenu] = useState('dashboard');

  const fetchData = async () => {
    try {
      const [resTrash, resAdmins, resStats] = await Promise.all([
        fetch('http://127.0.0.1:5000/api/trash'),
        fetch('http://127.0.0.1:5000/api/admins'),
        fetch('http://127.0.0.1:5000/api/trash/daily-stats')
      ]);
      setTrashData(await resTrash.json());
      setAdminData(await resAdmins.json());
      setDailyStats(await resStats.json());
    } catch (error) {
      console.error("Fetch error:", error);
    }
  };

  const handleDeleteAdmin = async (email) => {
    if (window.confirm(`Hapus admin ${email}?`)) {
      try {
        const res = await fetch(`http://127.0.0.1:5000/api/admins/${email}`, { method: 'DELETE' });
        if (res.ok) { alert("Dihapus!"); fetchData(); }
      } catch (e) { alert("Gagal!"); }
    }
  };

  useEffect(() => {
    setActiveAdmin(localStorage.getItem("nama_aktif") || "Admin");
    fetchData();
    const interval = setInterval(fetchData, 5000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div style={styles.appContainer}>
      <style>
        {`
          @import url('https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:wght@300;400;600;800&display=swap');
          * { font-family: 'Plus Jakarta Sans', sans-serif; transition: all 0.3s ease; }
          tr:hover { background-color: #f8fbf9 !important; transform: scale(1.002); }
          button:hover { filter: brightness(1.1); transform: translateY(-1px); }
        `}
      </style>

      {/* --- SIDEBAR --- */}
      <aside style={styles.sidebar}>
        <div style={styles.logoArea}>
          <div style={styles.logoIcon}>S</div>
          <span style={styles.logoText}>SMART BIN</span>
        </div>

        <nav style={styles.navMenu}>
          <NavItem active={activeMenu === 'dashboard'} label="Dashboard" icon="📊" onClick={() => setActiveMenu('dashboard')} />
          <NavItem active={activeMenu === 'admin'} label="Manajemen Admin" icon="👥" onClick={() => setActiveMenu('admin')} />

          <div style={styles.sidebarSectionLabel}>DATA REAL-TIME</div>
          <div style={styles.miniLogList}>
            {trashData.slice(0, 3).map((log, i) => (
              <div key={i} style={styles.miniLogItem}>
                <span>{log.bin_id}</span>
                <span style={{color: log.percentage > 85 ? '#ff4d4d' : '#2ecc71'}}>{Math.round(log.percentage)}%</span>
              </div>
            ))}
          </div>

          <div style={styles.logoutBtn} onClick={() => { localStorage.clear(); window.location.href = "/"; }}>
            <span style={{marginRight: '10px'}}>🚪</span> Keluar Sistem
          </div>
        </nav>
      </aside>

      {/* --- MAIN CONTENT --- */}
      <main style={styles.mainContent}>
        <header style={styles.topHeader}>
          <div style={styles.breadcrumb}>Utama / {activeMenu === 'dashboard' ? 'Monitoring' : 'Admin'}</div>
          <div style={styles.userProfile}>
            <div style={{textAlign: 'right', marginRight: '12px'}}>
              <div style={{fontSize: '14px', fontWeight: '800', color: '#2d3436'}}>{activeAdmin}</div>
              <div style={{fontSize: '11px', color: '#636e72'}}>Administrator</div>
            </div>
            <div style={styles.avatar}>👤</div>
          </div>
        </header>

        <div style={styles.contentWrapper}>
          <h2 style={styles.welcomeText}>
            {activeMenu === 'dashboard' ? 'Pemantauan Sampah' : 'Pengaturan Akses'}
          </h2>

          {activeMenu === 'dashboard' ? (
            <>
              <div style={styles.statsGrid}>
                <StatCard icon="🗑️" value={trashData.length} label="Total Log" color="#008f68" />
                <StatCard icon="👤" value={adminData.length} label="Admin" color="#0984e3" />
                <StatCard icon="⚡" value="Online" label="Status" color="#2ecc71" />
              </div>

              <div style={styles.dailySection}>
                <h3 style={styles.sectionTitle}>📅 Aktivitas 5 Hari Terakhir</h3>
                <div style={styles.dailyRow}>
                  {dailyStats.slice(0, 5).map((s, i) => (
                    <div key={i} style={styles.dailyCard}>
                      <div style={{fontSize: '12px', color: '#636e72'}}>{s.date}</div>
                      <div style={{fontSize: '20px', fontWeight: '800', color: '#008f68'}}>{s.count} Log</div>
                    </div>
                  ))}
                </div>
              </div>

              <div style={styles.tableCard}>
                <h3 style={styles.sectionTitle}>📊 Tabel Kapasitas</h3>
                <table style={styles.table}>
                  <thead>
                    <tr>
                      <th style={styles.th}>ID BIN</th>
                      <th style={styles.th}>PERSENTASE</th>
                      <th style={styles.th}>JENIS</th>
                      <th style={styles.th}>KONDISI</th>
                      <th style={styles.th}>AKSI</th>
                    </tr>
                  </thead>
                  <tbody>
                    {trashData.map((item, index) => (
                      <tr key={index} style={{ borderBottom: '1px solid #f1f2f6' }}>
                        <td style={{ ...styles.td, fontWeight: '700' }}>{item.bin_id}</td>
                        <td style={styles.td}><CapacityBar percentage={item.percentage} /></td>
                        <td style={styles.td}><span style={styles.typeTag}>{item.type}</span></td>
                        <td style={styles.td}>
                          <span style={item.status === 'penuh' ? styles.badgeRed : styles.badgeGreen}>{item.status}</span>
                        </td>
                        <td style={styles.td}>
                          <button style={styles.actionBtn}>Detail</button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </>
          ) : (
            <div style={styles.tableCard}>
              <h3 style={styles.sectionTitle}>👥 Daftar Pengelola</h3>
              <table style={styles.table}>
                <thead>
                  <tr>
                    <th style={styles.th}>NAMA</th>
                    <th style={styles.th}>EMAIL</th>
                    <th style={styles.th}>AKSI</th>
                  </tr>
                </thead>
                <tbody>
                  {adminData.map((admin, index) => (
                    <tr key={index}>
                      <td style={{ ...styles.td, fontWeight: '700' }}>{admin.name}</td>
                      <td style={styles.td}>{admin.email}</td>
                      <td style={styles.td}>
                        {admin.name !== activeAdmin ? (
                          <button onClick={() => handleDeleteAdmin(admin.email)} style={styles.delBtn}>Hapus</button>
                        ) : (
                          <span style={{fontSize: '12px', color: '#b2bec3'}}>Akun Anda</span>
                        )}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </main>
    </div>
  );
}

const NavItem = ({ active, label, icon, onClick }) => (
  <div style={active ? styles.navItemActive : styles.navItem} onClick={onClick}>
    <span style={{marginRight: '12px', fontSize: '18px'}}>{icon}</span> {label}
  </div>
);

const styles = {
  appContainer: { display: 'flex', minHeight: '100vh', backgroundColor: '#f0f3f7' },
  sidebar: { width: '280px', backgroundColor: '#008f68', color: '#fff', padding: '40px 0', display: 'flex', flexDirection: 'column', boxShadow: '4px 0 20px rgba(0,0,0,0.1)' },
  logoArea: { padding: '0 30px', marginBottom: '50px', display: 'flex', alignItems: 'center', gap: '15px' },
  logoIcon: { background: '#fff', color: '#008f68', width: '40px', height: '40px', borderRadius: '12px', display: 'flex', justifyContent: 'center', alignItems: 'center', fontWeight: '800', fontSize: '22px' },
  logoText: { fontSize: '18px', fontWeight: '800', letterSpacing: '1px' },
  navMenu: { flex: 1 },
  navItem: { padding: '15px 30px', cursor: 'pointer', color: '#c1e1d8', display: 'flex', alignItems: 'center', fontSize: '14px', fontWeight: '500' },
  navItemActive: { padding: '15px 30px', cursor: 'pointer', background: 'rgba(255,255,255,0.1)', borderLeft: '6px solid #fff', color: '#fff', fontSize: '14px', fontWeight: '700' },
  sidebarSectionLabel: { padding: '30px 30px 10px', fontSize: '11px', fontWeight: '800', opacity: 0.5, letterSpacing: '1px' },
  miniLogList: { padding: '0 30px' },
  miniLogItem: { background: 'rgba(0,0,0,0.1)', padding: '10px 15px', borderRadius: '10px', marginBottom: '8px', fontSize: '12px', display: 'flex', justifyContent: 'space-between' },
  logoutBtn: { margin: 'auto 30px 0', padding: '15px', borderRadius: '12px', background: '#e74c3c', color: '#fff', textAlign: 'center', cursor: 'pointer', fontWeight: '700', fontSize: '14px' },

  mainContent: { flex: 1, padding: '40px', overflowY: 'auto' },
  topHeader: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '40px' },
  breadcrumb: { color: '#636e72', fontSize: '13px', fontWeight: '600' },
  userProfile: { display: 'flex', alignItems: 'center', background: '#fff', padding: '8px 15px', borderRadius: '15px', boxShadow: '0 4px 12px rgba(0,0,0,0.03)' },
  avatar: { width: '35px', height: '35px', borderRadius: '10px', background: '#f1f2f6', display: 'flex', justifyContent: 'center', alignItems: 'center' },

  welcomeText: { fontSize: '28px', fontWeight: '800', color: '#2d3436', marginBottom: '35px' },
  statsGrid: { display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '25px', marginBottom: '40px' },
  statCard: { background: '#fff', padding: '25px', borderRadius: '24px', display: 'flex', alignItems: 'center', gap: '20px', boxShadow: '0 10px 25px rgba(0,0,0,0.02)' },
  statIconBox: { width: '55px', height: '55px', borderRadius: '18px', display: 'flex', justifyContent: 'center', alignItems: 'center', fontSize: '24px' },
  statValue: { fontSize: '24px', fontWeight: '800', color: '#2d3436' },
  statLabel: { fontSize: '13px', color: '#636e72', fontWeight: '600' },

  dailySection: { marginBottom: '40px' },
  sectionTitle: { fontSize: '18px', fontWeight: '800', color: '#2d3436', marginBottom: '20px' },
  dailyRow: { display: 'flex', gap: '15px' },
  dailyCard: { background: '#fff', padding: '20px', borderRadius: '20px', flex: 1, textAlign: 'center', boxShadow: '0 4px 15px rgba(0,0,0,0.02)' },

  tableCard: { background: '#fff', padding: '30px', borderRadius: '24px', boxShadow: '0 15px 35px rgba(0,0,0,0.03)' },
  table: { width: '100%', borderCollapse: 'collapse' },
  th: { textAlign: 'left', padding: '15px', color: '#b2bec3', fontSize: '11px', fontWeight: '800', textTransform: 'uppercase', letterSpacing: '1px' },
  td: { padding: '18px 15px', fontSize: '14px', color: '#2d3436' },

  typeTag: { background: '#f1f2f6', padding: '5px 12px', borderRadius: '8px', fontSize: '12px', fontWeight: '700', color: '#636e72' },
  progressBar: { width: '100px', height: '8px', background: '#f1f2f6', borderRadius: '10px', overflow: 'hidden' },
  progressFill: { height: '100%', borderRadius: '10px' },
  badgeGreen: { background: '#ebfaf0', color: '#2ecc71', padding: '6px 14px', borderRadius: '10px', fontSize: '12px', fontWeight: '800' },
  badgeRed: { background: '#fff0f0', color: '#ff4d4d', padding: '6px 14px', borderRadius: '10px', fontSize: '12px', fontWeight: '800' },
  actionBtn: { background: '#008f68', color: '#fff', border: 'none', padding: '8px 18px', borderRadius: '10px', cursor: 'pointer', fontWeight: '700', fontSize: '12px' },
  delBtn: { background: '#ff7675', color: '#fff', border: 'none', padding: '8px 18px', borderRadius: '10px', cursor: 'pointer', fontWeight: '700', fontSize: '12px' },
};

export default Dashboard;
